import "./textarea.css";

import { cn } from "tailwind-variants";

import { textareaVariants, type TextareaVariants } from "./textarea.variants";

export type TextareaProps = React.ComponentProps<"textarea"> & TextareaVariants;

export const Textarea = ({ className, ...props }: TextareaProps) => {
  return <textarea className={cn(textareaVariants(), className)} {...props} />;
};

import { tv, type VariantProps } from "tailwind-variants";

export const textareaVariants = tv({
  base: "textarea",
});

export type TextareaVariants = VariantProps<typeof textareaVariants>;

.textarea {
  @apply border-input bg-background text-foreground placeholder:text-muted-foreground flex min-h-[60px] w-full rounded-md border px-3 py-2 text-sm shadow-sm transition-colors;

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }

  &:disabled {
    @apply cursor-not-allowed opacity-50;
  }
}

import { Textarea, type TextareaProps } from "./textarea";
import { type TextareaVariants, textareaVariants } from "./textarea.variants";

export { Textarea, textareaVariants };

export type { TextareaProps, TextareaVariants };
